/**
 * THE PALETTE SHOP — the six purchasable whole-app colour palettes plus the
 * free 'standard' identity (2026-07-17).
 *
 * Each palette is a FULL record of tokens.colors' keys: the 15 chrome tokens
 * (bg, bg-deep, surface×3, border×3, text×3, accent×4) are re-hued; the five
 * rarity tokens and success/warn/danger are ALWAYS standard — rarity is a
 * cross-app vocabulary and semantic colours encode meaning (a theme that
 * turns "danger" green is a correctness bug). Pinned by
 * __tests__/palettes.test.ts.
 *
 * Generated by the scratchpad gen_palettes.py (HSL hue rotation preserving
 * each token's lightness/saturation relationships; contrast-checked
 * text/surface >= 4.5:1, text-mute/surface >= 3:1), then hand-tuned:
 * accent-ink stays near-black in every palette (it is the text ON accent
 * fills) and void's accent family is lifted to white ("white accent" is the
 * product spec for Void Mono).
 *
 * Colours live HERE; ids and prices live in domain/customise.ts
 * (PALETTE_IDS / PALETTE_PRICES — the server's palette_price() is the
 * authority, the domain table is its display twin). The vitest pins the two
 * id sets equal in both directions.
 */
// Relative on purpose: this module is imported by vitest (no @/ alias there).
import tokens from './tokens';

export type PaletteColours = typeof tokens.colors;

