export type ThemePaletteId = keyof typeof PALETTE_COLOURS;

export const THEME_PALETTE_IDS = Object.keys(PALETTE_COLOURS) as ThemePaletteId[];

/** Store-card metadata: display name + four swatches (bg, surface-2, accent, text). */
export const PALETTE_META: Record<ThemePaletteId, { name: string; swatch: [string, string, string, string] }> =
  Object.fromEntries(
    (
      [
        ['standard', 'STANDARD ISSUE'],
        ['emerald', 'EMERALD CIRCUIT'],
        ['crimson', 'CRIMSON EMBER'],
        ['synthwave', 'SYNTHWAVE'],
        ['solar', 'SOLAR FLARE'],
        ['arctic', 'ARCTIC GHOST'],
        ['void', 'VOID MONO'],
      ] as const
    ).map(([id, name]) => {
      const c = PALETTE_COLOURS[id];
      return [id, { name, swatch: [c.bg, c['surface-2'], c.accent, c.text] }];
    })
  ) as Record<ThemePaletteId, { name: string; swatch: [string, string, string, string] }>;

export function isThemePaletteId(id: string | null | undefined): id is ThemePaletteId {
  return id != null && Object.prototype.hasOwnProperty.call(PALETTE_COLOURS, id);
}

/**
 * The CSS custom properties ThemeRoot applies. 'standard' returns {} —
 * unset vars mean every `var(--c-k, fallback)` in the compiled CSS resolves
 * to its fallback, which IS the standard value (provably identical, and the
 * cheapest possible default).
 */
export function varsFor(id: ThemePaletteId): Record<string, string> {
  if (id === 'standard') return {};
  const record = PALETTE_COLOURS[id];
  return Object.fromEntries(Object.entries(record).map(([k, v]) => [`--c-${k}`, v]));
}
